import { NextRequest, NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import path from "path";
import { PDFDocument } from "pdf-lib"; // For extracting images
import Tesseract from "tesseract.js"; // For OCR
import fs from "fs/promises"

const uploadDir = path.join(process.cwd(), "public", "uploads");

async function ensureUploadDir() {
  try {
    await fs.access(uploadDir);
  } catch {
    await fs.mkdir(uploadDir, { recursive: true });
  }
}

export async function POST(req: NextRequest) {
  try {
    await ensureUploadDir();
    const formData = await req.formData();
    const file = formData.get("file");

    if (!file || !(file instanceof File)) {
      return NextResponse.json(
        { message: "No file provided" },
        { status: 400 }
      );
    }

    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);

    // Generate a unique filename
    const uniqueFilename = `${Date.now()}-${file.name}`;
    const filepath = path.join(uploadDir, uniqueFilename);

    // Save the uploaded file
    await writeFile(filepath, buffer);

    // Extract text using PDF parsing and OCR
    let extractedText = await extractTextFromPDF(filepath, buffer);

    // Check if the extracted text contains marksheet-related keywords
    const isMarksheet = checkIfMarksheet(extractedText);

    return NextResponse.json({ text: extractedText, isMarksheet });
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { message: "Error processing file" },
      { status: 500 }
    );
  }
}

// Extract text using both PDF text parsing and OCR
async function extractTextFromPDF(filePath, buffer) {
  try {
    // Try to extract text from PDF directly (if it's a selectable text PDF)
    const text = await extractTextDirectly(buffer);
    if (text.trim()) return text;

    // If no text is found, use OCR
    console.log("No text found, using OCR...");
    return await performOCR(filePath);
  } catch (error) {
    console.error("Error extracting text:", error);
    return "";
  }
}

// Extract text directly from PDF (if text is selectable)
async function extractTextDirectly(buffer) {
  try {
    const pdfDoc = await PDFDocument.load(buffer);
    let extractedText = "";
    for (const page of pdfDoc.getPages()) {
      extractedText += page.getTextContent() + "\n";
    }
    return extractedText;
  } catch (error) {
    console.error("Failed to extract text directly:", error);
    return "";
  }
}

// Perform OCR using tesseract.js
async function performOCR(filePath) {
  try {
    const { data } = await Tesseract.recognize(filePath, "eng");
    return data.text;
  } catch (error) {
    console.error("OCR failed:", error);
    return "";
  }
}

// Check if extracted text contains marksheet-related keywords
function checkIfMarksheet(text) {
  const keywords = [
    "percentage",
    "marks",
    "subject",
    "grade",
    "total",
    "obtained",
  ];
  return keywords.some((word) => text.toLowerCase().includes(word));
}
